package com.archivenexus.backend.web;
import com.archivenexus.backend.scenario.ScenarioService;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/scenarios") public class ScenarioController{private final ScenarioService scenarios;public ScenarioController(ScenarioService scenarios){this.scenarios=scenarios;}@PostMapping("/{id}/run") ResponseEntity<ScenarioService.ScenarioResult> run(@PathVariable String id,@RequestBody(required=false) ScenarioRequest request){String factory=request==null?null:request.factoryId();String actor=request==null?"operator":request.requestedBy();return ResponseEntity.accepted().body(scenarios.run(id,factory,actor));}public record ScenarioRequest(String factoryId,String requestedBy){}}
